external_knowledge:
- 'active users' refers to those users whose account status is 'active';
- 'voyages through the portal' metaphorically refers to access events or logins;
- 'depth of their exploration' metaphorically refers to the total number of access events by a user.

- Fluctuations in case numbers refer to changes in the number of confirmed cases over time;
- The change in vaccination rates over time is an indicator of the effectiveness of vaccination campaigns;
- Change in fatalities refers to the difference in the number of deaths from one period to the next.

- 'user_id = 1' refers to a specific individual; 
- 'access_date' is the date when the user accessed the data;
- 'response_date' indicates when the system responded to an issue related to the data from a certain country.

sql:
SELECT trend_description
FROM trends
WHERE impact_factor = (SELECT MAX(impact_factor) FROM trends);

SELECT c.country_name, h.recovered_cases
FROM countries c
JOIN health_metrics h ON c.country_id = h.country_id
WHERE h.recovered_cases = (
    SELECT MAX(recovered_cases) FROM health_metrics
);

SELECT AVG(impact_factor) AS average_impact_factor 
FROM trends 
WHERE trend_type = 'positive';

SELECT *
FROM trends t
WHERE t.metric_id = 'specific_metric_id' AND t.trend_type = 'specific_trend_type';

SELECT country_name, last_updated
FROM countries
ORDER BY last_updated DESC;
